#detail_list@img@html||source@src@js:
var imgReg = /\.(jpg|jpeg|png|gif|webp|bmp)$/i;
var videoReg = /\.(m3u8|mp4|flv|avi|mkv)$/i;
var pathReg = /\/p=\d+\//g;
var linkList = [];
var finalContent = '';

// 兼容Legado原生返回的Java列表/JS数组/单条字符串，彻底解决多结果处理失效
if (result != null && result != undefined) {
  if (typeof result.size === 'function' && typeof result.get === 'function') {
    for (var i = 0; i < result.size(); i++) linkList.push(result.get(i) + '');
  } else if (Array.isArray(result)) {
    linkList = result;
  } else {
    linkList.push(result + '');
  }
}

// 路径修复函数，自动去除/p=数字/
function fixImgUrl(url) {
  if (!url) return url;
  try {
    return decodeURIComponent(url).replace(pathReg, '/');
  } catch (e) {
    return url.replace(pathReg, '/');
  }
}

for (var i = 0; i < linkList.length; i++) {
  var link = linkList[i];
  if (!link) continue;

  // 图片处理：路径修复+仅显示不跳转，彻底解决跳转播放器问题
  if (imgReg.test(link)) {
    var fixedLink = fixImgUrl(link);
    finalContent += '【刷新正文】查看\n✅原图:\n<img src="' + fixedLink + '" style="max-width:100%;margin:8px 0;display:block;" />\n\n';
  }
  // 视频处理：完全保留你原本能用的所有逻辑，一丝未改
  else if (videoReg.test(link)) {
    // 加容错避免非当前章节报错导致JS中断
    if (typeof book != 'undefined' && typeof chapter != 'undefined' && book.durChapterIndex == chapter.index) {
      try {
        java.startBrowser(link, title);
        java.toast('正在加载视频\n视频加载较慢，请耐心等待');
      } catch (e) {}
    }
    finalContent += '【刷新正文】播放\n✅直链:\n' + link + ',{"webView": true}\n\n';
  }
  // 其他链接兜底
  else {
    finalContent += '【刷新正文】查看\n✅链接:\n' + link + '\n\n';
  }
}

finalContent;
